# JSON Data Normalization & Cleaning Function

Berikut implementasi lengkap untuk normalisasi dan pembersihan JSON data dari API dengan pertimbangan keamanan:

## Python Implementation

```python
import json
import re
from typing import Any, Dict, Optional
from datetime import datetime

class JSONCleaner:
    """Security-focused JSON data normalizer for API responses"""

    # Dangerous patterns that could indicate XSS/Injection
    DANGEROUS_PATTERNS = [
        r'<script[^>]*>.*?</script>',
        r'javascript:',
        r'on\w+\s*=',
        r'<iframe[^>]*>',
        r'<object[^>]*>',
        r'expression\s*\(',
    ]

    def __init__(self, max_depth: int = 10, max_string_length: int = 10000):
        self.max_depth = max_depth
        self.max_string_length = max_string_length

    def clean(self, data: Any, depth: int = 0) -> Any:
        """Recursively clean and normalize JSON data"""
        if depth > self.max_depth:
            raise ValueError(f"Max depth {self.max_depth} exceeded")

        if data is None:
            return None

        if isinstance(data, str):
            return self._clean_string(data)

        if isinstance(data, bool):
            return data

        if isinstance(data, (int, float)):
            return self._validate_number(data)

        if isinstance(data, list):
            return [self.clean(item, depth + 1) for item in data]

        if isinstance(data, dict):
            return self._clean_dict(data, depth)

        # Unknown type - convert to string safely
        return self._clean_string(str(data))

    def _clean_string(self, value: str) -> str:
        """Sanitize string values"""
        if not value:
            return ""

        # Truncate excessive length
        if len(value) > self.max_string_length:
            value = value[:self.max_string_length]

        # Strip whitespace
        value = value.strip()

        # Remove dangerous HTML/JS patterns (XSS prevention)
        for pattern in self.DANGEROUS_PATTERNS:
            value = re.sub(pattern, '', value, flags=re.IGNORECASE | re.DOTALL)

        # Normalize unicode
        value = value.encode('utf-8', errors='ignore').decode('utf-8')

        return value

    def _validate_number(self, value: float) -> float:
        """Validate numeric values"""
        import math

        # Check for NaN, Infinity
        if math.isnan(value) or math.isinf(value):
            return 0

        # Reasonable bounds check
        if abs(value) > 1e15:
            raise ValueError(f"Number out of reasonable bounds: {value}")

        return value

    def _clean_dict(self, data: Dict, depth: int) -> Dict:
        """Clean dictionary with key normalization"""
        cleaned = {}

        for key, value in data.items():
            # Normalize keys (lowercase, strip, alphanumeric + underscore)
            clean_key = re.sub(r'[^a-zA-Z0-9_]', '', str(key).lower().strip())

            if not clean_key:
                continue  # Skip invalid keys

            # Skip potentially dangerous keys
            if clean_key.startswith('__'):
                continue

            cleaned[clean_key] = self.clean(value, depth + 1)

        return cleaned

    def parse_and_clean(self, raw_data: str) -> Dict:
        """Parse JSON string and clean the result"""
        try:
            data = json.loads(raw_data)
        except json.JSONDecodeError as e:
            raise ValueError(f"Invalid JSON: {str(e)}")

        return self.clean(data)


# Usage Example
def fetch_and_process_api_data(api_response: str) -> Dict:
    """Process API response with security cleaning"""
    cleaner = JSONCleaner(max_depth=10, max_string_length=5000)

    try:
        cleaned_data = cleaner.parse_and_clean(api_response)

        # Add metadata
        cleaned_data['_processed_at'] = datetime.utcnow().isoformat()
        cleaned_data['_sanitized'] = True

        return cleaned_data

    except Exception as e:
        # Log error, return safe default
        return {
            '_error': str(e),
            '_processed_at': datetime.utcnow().isoformat(),
            '_sanitized': True
        }


# Test
