    test_json = '''
    {
        "user_name": "  John Doe  ",
        "email": "john@example.com",
        "bio": "<script>alert('XSS')</script>Normal text",
        "age": 25,
        "scores": [95, 87, 92],
        "metadata": {
            "__proto__": "dangerous",
            "ip": "192.168.1.1"
        }
    }
    '''

    result = fetch_and_process_api_data(test_json)
    print(json.dumps(result, indent=2))
```

## PHP Implementation

```php
<?php

class JSONCleaner {
    private int $maxDepth = 10;
    private int $maxStringLength = 10000;

    private array $dangerousPatterns = [
        '/<script[^>]*>.*?<\/script>/is',
        '/javascript:/i',
        '/on\w+\s*=/i',
        '/<iframe[^>]*>/i',
        '/<object[^>]*>/i',
        '/expression\s*\(/i',
    ];

    public function __construct(int $maxDepth = 10, int $maxStringLength = 10000) {
        $this->maxDepth = $maxDepth;
        $this->maxStringLength = $maxStringLength;
    }

    public function clean(mixed $data, int $depth = 0): mixed {
        if ($depth > $this->maxDepth) {
            throw new InvalidArgumentException("Max depth {$this->maxDepth} exceeded");
        }

        if ($data === null) {
            return null;
        }

        if (is_string($data)) {
            return $this->cleanString($data);
        }

        if (is_bool($data) || is_int($data) || is_float($data)) {
            return $this->validateNumber($data);
        }

        if (is_array($data)) {
            // Check if associative or indexed
            if (array_keys($data) === range(0, count($data) - 1)) {
                return array_map(fn($item) => $this->clean($item, $depth + 1), $data);
            }
            return $this->cleanDict($data, $depth);
        }

        // Unknown type
        return $this->cleanString((string)$data);
    }

    private function cleanString(string $value): string {
        if (empty($value)) {
            return "";
        }

        // Truncate
        if (strlen($value) > $this->maxStringLength) {
            $value = substr($value, 0, $this->maxStringLength);
        }

        // Trim
        $value = trim($value);

        // Remove dangerous patterns
        foreach ($this->dangerousPatterns as $pattern) {
            $value = preg_replace($pattern, '', $value);
        }

        // Normalize UTF-8
        $value = mb_convert_encoding($value, 'UTF-8', 'UTF-8');

        return $value;
    }

    private function validateNumber(int|float $value): int|float {
        if (is_nan($value) || is_infinite($value)) {
            return 0;
        }

        if (abs($value) > 1e15) {
            throw new InvalidArgumentException("Number out of reasonable bounds");
        }

        return $value;
    }

    private function cleanDict(array $data, int $depth): array {
        $cleaned = [];

        foreach ($data as $key => $value) {
            // Normalize key
            $cleanKey = preg_replace('/[^a-zA-Z0-9_]/', '', strtolower(trim($key)));

            if (empty($cleanKey) || str_starts_with($cleanKey, '__')) {
                continue;
            }

            $cleaned[$cleanKey] = $this->clean($value, $depth + 1);
        }

        return $cleaned;
    }

    public function parseAndClean(string $rawData): array {
        $data = json_decode($rawData, true);

        if (json_last_error() !== JSON_ERROR_NONE) {
            throw new InvalidArgumentException("Invalid JSON: " . json_last_error_msg());
        }

        return $this->clean($data);
    }
}

// Usage
function processAPIResponse(string $response): array {
    $cleaner = new JSONCleaner(10, 5000);

    try {
        $cleaned = $cleaner->parseAndClean($response);
        $cleaned['_processed_at'] = date('c');
        $cleaned['_sanitized'] = true;
        return $cleaned;
    } catch (Exception $e) {
        return [
            '_error' => $e->getMessage(),
            '_processed_at' => date('c'),
            '_sanitized' => true
        ];
    }
}
